def _id(n,p): return "opp_"+hashlib.md5(f"{n}{p}".encode()).hexdigest()[:10]
def _due(d): return (datetime.now()+timedelta(days=d)).strftime("%Y-%m-%d")
def _fixed(m,d):
    yr=datetime.now().year; dt=datetime(yr,m,d)
    if dt<datetime.now(): dt=datetime(yr+1,m,d)
    return dt.strftime("%Y-%m-%d")

def _o(t,name,prov,url,amt,dl,deg,ctry,maj,gpa,need,essay,req,elig,src,country,tags=None,diff="medium",accept=0.0,avg_app=0,duration=0,note=""):
    m=MOBILITY.get(country,MOBILITY["Various"])
    return {"id":_id(name,prov),"opportunity_type":t,"name":name,"provider":prov,"url":url,
            "amount_usd":float(amt),"amount_note":note,"deadline":dl,"deadline_rolling":False,
            "degree_levels":deg if isinstance(deg,list) else [deg],
            "eligible_countries":ctry,"major_restrictions":maj,"gpa_min":float(gpa),
            "financial_need":bool(need),"essay_prompt":essay,"requirements":req,"eligibility":elig,
            "source":src,"tags":(tags or[])+["direct-portal",t],"verified":True,"status":"open",
            "duration_weeks":duration,"location_country":country,"location_city":"","remote_ok":country=="Online",
            "difficulty":diff,"acceptance_rate":float(accept),"avg_applicants":int(avg_app),
            "visa_required":m["vis"],"visa_type":m["vtype"],"work_permitted":m["work"],
            "living_cost_monthly":m["cost"],"stipend_included":m["stip"],"housing_included":m["hous"]}

