def match_opportunities(profile: dict, opp_type: str=None, min_amount: float=0) -> list[dict]:
    all_opps=load_all_opportunities()
    country=(profile.get("nationality") or "Kenya").lower()
    degree=(profile.get("degree_level") or "Graduate").lower()
    gpa=float(profile.get("gpa") or 0)
    major=(profile.get("major") or "").lower()
    results=[]
    for opp in all_opps:
        if opp_type and opp["opportunity_type"]!=opp_type: continue
        if opp["amount_usd"]<min_amount: continue
        if opp.get("deadline"):
            try:
                days=(datetime.strptime(opp["deadline"],"%Y-%m-%d")-datetime.now()).days
                if days<0: continue
                opp["days_left"]=days
            except: opp["days_left"]=365
        else: opp["days_left"]=365
        ctry=[c.lower() for c in opp.get("eligible_countries",[])]
        country_ok=(not ctry or any(c in["all countries","all","worldwide","global"]for c in ctry) or
            any(country in c or c in country for c in ctry) or
            ("africa" in" ".join(ctry) and any(k in country for k in["kenya","nigeria","ghana","ethiopia","rwanda","uganda","tanzania","africa"])) or
            any("all" in c for c in ctry))
        deg=[d.lower() for d in opp.get("degree_levels",[])]
        degree_ok=(not deg or any(degree[:4] in d or d[:4] in degree for d in deg) or "any" in" ".join(deg))
        if not(country_ok and degree_ok): continue
        score=0.5
        gpa_min=float(opp.get("gpa_min") or 0)
        if gpa>=gpa_min: score+=0.15*min(1.0,(gpa-gpa_min)/max(0.1,4.0-gpa_min))
        else: score-=0.2
        if opp.get("financial_need")==profile.get("financial_need"): score+=0.1
        maj_reqs=[m.lower() for m in opp.get("major_restrictions",[])]
        if not maj_reqs or any(major in m or m in major for m in maj_reqs): score+=0.1
        score+=0.05*min(1.0,opp["amount_usd"]/50000)
        if opp["days_left"]<30: score+=0.1
        elif opp["days_left"]<90: score+=0.05
        opp["match_score"]=round(max(0.0,min(1.0,score)),3)
        results.append(opp)
    results.sort(key=lambda x:(-x["match_score"],x["days_left"],-x["amount_usd"]))
    return results
